import os
from anthropic import Anthropic

client = Anthropic()

# 1. Define tools using JSON Schema format
tools = [
    {
        "name": "get_weather",
        "description": "Get the current weather for a given city.",
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {
                    "type": "string",
                    "description": "The city name, e.g. 'San Francisco'"
                }
            },
            "required": ["city"]
        }
    }
]


def execute_tool(tool_name: str, tool_input: dict) -> str:
    """Dispatch tool calls to the appropriate implementation."""
    if tool_name == "get_weather":
        # In production, call a real weather API here
        city = tool_input["city"]
        return f"The weather in {city} is 22°C and sunny."
    return f"Unknown tool: {tool_name}"


def run_agent(user_message: str) -> str:
    """Run a multi-turn agent loop until the model stops calling tools."""
    messages = [{"role": "user", "content": user_message}]

    while True:
        # 2. Call the API
        response = client.messages.create(
            model="claude-opus-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )

        # 3. Check stop reason
        if response.stop_reason == "end_turn":
            # Model finished — extract the final text response
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        if response.stop_reason == "tool_use":
            # 4. Append assistant's response to the conversation
            messages.append({"role": "assistant", "content": response.content})

            # 5. Execute all tool calls and collect results
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })

            # 6. Append tool results and loop
            messages.append({"role": "user", "content": tool_results})

        else:
            # Unexpected stop reason — break to avoid infinite loop
            break

    return ""


if __name__ == "__main__":
    answer = run_agent("What is the weather like in Tokyo and Paris today?")
    print(answer)
